import android.app.Activity;
import android.os.Bundle;
import android.view.View;
import android.widget.Button;
import android.widget.EditText;
import android.widget.TextView;

public class BankingApp extends Activity {
    private static final String BALANCE = "balance";

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_banking_app);

        // Initialize views
        Button depositButton = findViewById(R.id.deposit_button);
        EditText amountEditText = findViewById(R.id.amount_edittext);
        TextView balanceTextView = findViewById(R.id.balance_textview);

        // Set listener for deposit button
        depositButton.setOnClickListener(new View.OnClickListener() {
            @Override
            public void onClick(View v) {
                String amountString = amountEditText.getText().toString();
                int amount = Integer.parseInt(amountString);

                // Perform transaction and update balance
                int newBalance = performTransaction(amount);
                balanceTextView.setText(Integer.toString(newBalance));
            }
        });
    }

    private int performTransaction(int amount) {
        // Simulate a simple transaction processing logic for now
        return amount + 5;
    }
}